/* Custom checkbox -- native checkbox with appearance stripped */
.todo-item__toggle input[type="checkbox"] {
  appearance: none;
  -webkit-appearance: none;
  inline-size: 1.25rem;
  block-size: 1.25rem;
  flex-shrink: 0;
  border: 2px solid var(--color-border-strong);
  border-radius: var(--radius-sm);
  background: var(--color-bg-raised);
  cursor: pointer;
  margin: 0;
}

.todo-item__toggle input[type="checkbox"]:checked {
  background-color: var(--color-primary);
  border-color: var(--color-primary);
}

/* Checkmark indicator using a rotated border trick */
.todo-item__toggle input[type="checkbox"]:checked::after {
  content: "";
  display: block;
  inline-size: 0.35rem;
  block-size: 0.65rem;
  margin-inline-start: 0.35rem;
  margin-block-start: 0.05rem;
  border: solid white;
  border-width: 0 2px 2px 0;
  transform: rotate(45deg);

